import React from "react";
import { useNavigate } from "react-router-dom";
import {
  LogOut,
  Home,
  User,
  Calendar,
  Users,
  MessageCircle,
  Briefcase,
  GraduationCap,
  Newspaper,
  Settings,
  Award,
  Heart,
  BookOpen,
  Phone,
} from "lucide-react";
import { useAuth } from "./AuthContext";

export default function Dashboard() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  const handleLogout = () => {
    logout();
    navigate("/");
  };

  const menuItems = [
    { label: "Profile", path: "/profile", icon: User },
    { label: "Events", path: "/events", icon: Calendar },
    { label: "Network", path: "/network", icon: Users },
    { label: "Messages", path: "/messages", icon: MessageCircle },
    { label: "Jobs", path: "/jobs", icon: Briefcase },
    { label: "Directory", path: "/directory", icon: GraduationCap },
    { label: "News", path: "/news", icon: Newspaper },
    { label: "Settings", path: "/settings", icon: Settings },
    { label: "Mentorship", path: "/mentorship", icon: BookOpen },
    { label: "Volunteer", path: "/volunteer", icon: Heart },
    { label: "Scholarships", path: "/scholarships", icon: Award },
    { label: "Testimonials", path: "/testimonials", icon: Users },
  ];

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <h1 className="text-2xl font-bold text-gray-900">Alumni Network</h1>
          <div className="flex items-center gap-4">
            <span className="text-gray-600">{user?.email || "Guest"}</span>
            <button
              onClick={handleLogout}
              className="flex items-center gap-2 text-red-600 hover:text-red-700 focus:outline-none focus:ring-2 focus:ring-red-500 rounded px-3 py-2"
              aria-label="Logout"
            >
              <LogOut className="w-5 h-5" /> Logout
            </button>
          </div>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <h2 className="text-3xl font-bold text-gray-900 mb-8">
          Welcome to Alumni Dashboard, {user?.name || "Alumni"}
        </h2>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {menuItems.map((item) => {
            const IconComponent = item.icon;
            return (
              <button
                key={item.path}
                onClick={() => navigate(item.path)}
                className="bg-white rounded-lg shadow p-6 hover:shadow-lg transition text-left hover:bg-blue-50 focus:outline-none focus:ring-2 focus:ring-blue-500 rounded-lg"
              >
                <IconComponent className="w-8 h-8 text-blue-600 mb-2" />
                <h3 className="font-semibold text-gray-900">{item.label}</h3>
              </button>
            );
          })}
        </div>

        {/* Quick Stats */}
        <div className="mt-12 grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-white rounded-lg shadow p-6">
            <Users className="w-8 h-8 text-blue-600 mb-2" />
            <h3 className="text-gray-600 text-sm font-medium">Connections</h3>
            <p className="text-3xl font-bold text-gray-900 mt-2">250+</p>
          </div>
          <div className="bg-white rounded-lg shadow p-6">
            <Calendar className="w-8 h-8 text-green-600 mb-2" />
            <h3 className="text-gray-600 text-sm font-medium">
              Upcoming Events
            </h3>
            <p className="text-3xl font-bold text-gray-900 mt-2">5</p>
          </div>
          <div className="bg-white rounded-lg shadow p-6">
            <Briefcase className="w-8 h-8 text-purple-600 mb-2" />
            <h3 className="text-gray-600 text-sm font-medium">
              Job Opportunities
            </h3>
            <p className="text-3xl font-bold text-gray-900 mt-2">28</p>
          </div>
        </div>
      </div>
    </div>
  );
}
